import type { PropsWithChildren } from 'react';
import React, { forwardRef, cloneElement } from 'react';
import clsx from 'clsx';
import type { StepsProps } from './interface';
import { isNonNullable, toFlatArray } from '../util';
import { useSteps, StepsContextProvider, useStepsContext } from './useSteps';
import { forwardHTMLRef } from '../util/forwardRef';
import NavigationIndicator from './NavigationIndicator';
import Description from './Description';
import stylex from '@universe-design/stylex';

const Descriptions = () => {
  const { steps, count, initial } = useStepsContext();

  const visibleSteps = steps.slice(0, count);
  return (
    <>
      {visibleSteps.map((step, index) => (
        <Description stepIndex={index + initial} key={index} />
      ))}
    </>
  );
};

const StepsContent = forwardHTMLRef<unknown, 'div'>((props, ref) => {
  const { children } = props;
  const {
    style,
    cssScope,
    fixedDirection,
    activeIndex,
    initial,
    preStatus,
    fixedLabelPlacement,
    type,
    status,
    separateDescription,
    className,
    size,
  } = useStepsContext();
  const childrenArray = toFlatArray(children);
  const childrenLength = childrenArray.length;
  const centerTitle =
    (fixedDirection === 'horizontal' && fixedLabelPlacement === 'horizontal') || type === 'navigation';

  const isDot = type === 'dot';

  const sxSteps = stylex.create({
    gridTemplateColumns: 'repeat(3, 1fr)',
  });
  const wrapperCls = clsx(
    cssScope(),
    cssScope(`--${fixedDirection}`),
    className,
    {
      [cssScope(`--${size}`)]: size,
      [cssScope('--navigation')]: type === 'navigation',
      [cssScope('--dot')]: isDot,
      [cssScope('--vertical-icon')]: fixedDirection === 'vertical' && !isDot,
      [cssScope(`--label-${fixedLabelPlacement}`)]: fixedDirection,
    },
    stylex(sxSteps),
  );

  return (
    <div
      className={wrapperCls}
      ref={ref}
      style={{
        ...style,
        alignItems: centerTitle ? 'center' : undefined,
        // columnGap: 8,
        gridTemplateColumns: fixedDirection === 'horizontal' ? `repeat(${childrenLength}, 1fr)` : '1fr',
      }}
    >
      {childrenArray.filter(isNonNullable).map((child, index) => {
        if (
          typeof child === 'string' ||
          typeof child === 'number' ||
          typeof child === 'boolean' ||
          !('props' in child)
        ) {
          return null;
        }
        const stepNumber = initial + index;
        const childProps = {
          key: index,
          prefixCls: cssScope(),
          stepIndex: stepNumber,
          ...child.props,
        };

        if (!child.props.status) {
          if (stepNumber < activeIndex) {
            childProps.status = 'finish';
          } else if (stepNumber === activeIndex) {
            childProps.status = status;
          } else {
            childProps.status = 'wait';
          }
        }

        const clx = clsx(
          {
            [cssScope('--next-error')]: status === 'error' && index === activeIndex - 1,
            [cssScope(`--pre-${preStatus}`)]: preStatus !== null,
          },
          childProps.className,
        );

        childProps.className = clx;

        // preStatus = childProps.status;

        return cloneElement(child, childProps);
      })}
      {separateDescription && <Descriptions />}
      {type === 'navigation'
        ? childrenArray.map((_, index) => <NavigationIndicator index={index} key={index} />)
        : null}
    </div>
  );
});

const Steps = forwardRef<HTMLDivElement, PropsWithChildren<StepsProps>>((props, ref) => {
  const { children } = props;
  const stepsCtxValue = useSteps(props);
  return (
    <StepsContextProvider value={stepsCtxValue}>
      <StepsContent ref={ref}>{children}</StepsContent>
    </StepsContextProvider>
  );
});
if (__DEV__) {
  Steps.displayName = 'Steps';
}

export default Steps;
